module top_module(selectInput, obf_out);output reg [7:0] obf_out;
input [2:0] selectInput;
always@(selectInput) begin
case(selectInput)
0: obf_out = 8'b00000001;
1: obf_out = 8'b00000010;
2: obf_out = 8'b00000100;
3: obf_out = 8'b00001000;
4: obf_out = 8'b00010000;
5: obf_out = 8'b00100000;
6: obf_out = 8'b01000000;
7: obf_out = 8'b10000000;
endcase
end
endmodule
